// THE DECISION (no AI). Routing reads ONLY the admin-confirmed content_type —
// never the LLM's suggestion. Mirrors src/lib/content/types.ts ROUTING and the
// publish_post RPC. Nothing becomes member-visible unless the admin confirmed a
// type AND pressed publish.
const d = $json;

// 1. The confirmed type is authoritative. NULL/empty = unconfirmed = NOT routable.
const confirmed = (d.admin_confirmed_type || '').trim();
const ROUTING = {
  meal_plan:     ['Essensplan (section)', 'post_details'],
  reflection:    ['Rückblick (section)', 'post_details'],
  health_notice: ['top-of-feed alert (by severity)'],
  event_notice:  ['events table', 'ICS calendar', 'Termine library'],
  info:          ['general feed']
};

let errors = [];
if (!ROUTING[confirmed]) errors.push('content_type not confirmed (NULL means unconfirmed) — cannot route');
if (!d.admin_pressed_publish) errors.push('admin has not pressed publish — stays draft');

const canPublish = errors.length === 0;
const destinations = canPublish ? ['Pinnwand (every published post)', ...ROUTING[confirmed]] : [];

return [{ json: {
  used_suggestion: d.content_type_suggested,        // shown for contrast
  used_confirmed: confirmed,                         // what routing ACTUALLY used
  routed_by_suggestion: false,                       // <-- the invariant
  can_publish: canPublish,
  blockers: errors,
  destinations,
  verdict: canPublish ? `PUBLISH -> ${destinations.join(' + ')}` : `BLOCKED: ${errors.join('; ')}`
}}];
